import{_ as s,o as n,c as t,a4 as l}from"./chunks/framework._in6GHBg.js";const x=JSON.parse('{"title":"导数详解","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Learn-Detail-003-导数详解-V1.0-20260405.md","filePath":"math/Math-Learn-Detail-003-导数详解-V1.0-20260405.md"}'),e={name:"math/Math-Learn-Detail-003-导数详解-V1.0-20260405.md"};function i(p,a,r,o,g,d){return n(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="导数详解" tabindex="-1">导数详解 <a class="header-anchor" href="#导数详解" aria-label="Permalink to &quot;导数详解&quot;">​</a></h1><p><strong>从&quot;平均变化&quot;到&quot;瞬时变化&quot;——微积分的起点</strong></p><hr><h2 id="一、本章地图" tabindex="-1">一、本章地图 <a class="header-anchor" href="#一、本章地图" aria-label="Permalink to &quot;一、本章地图&quot;">​</a></h2><h3 id="核心目标" tabindex="-1">核心目标 <a class="header-anchor" href="#核心目标" aria-label="Permalink to &quot;核心目标&quot;">​</a></h3><p>学完本章，你将：</p><ol><li>理解导数是瞬时变化率的数学表达</li><li>掌握导数的运算和几何意义</li><li>能用导数研究函数的性质（单调性、极值、最值）</li></ol><h3 id="知识网络" tabindex="-1">知识网络 <a class="header-anchor" href="#知识网络" aria-label="Permalink to &quot;知识网络&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>导数</span></span>
<span class="line"><span>├── 导数概念</span></span>
<span class="line"><span>│   ├── 平均变化率</span></span>
<span class="line"><span>│   ├── 瞬时变化率（导数）⭐</span></span>
<span class="line"><span>│   └── 导数的几何意义（切线斜率）</span></span>
<span class="line"><span>├── 导数运算</span></span>
<span class="line"><span>│   ├── 基本初等函数的导数</span></span>
<span class="line"><span>│   ├── 导数的四则运算</span></span>
<span class="line"><span>│   └── 复合函数求导（链式法则）⭐</span></span>
<span class="line"><span>└── 导数应用 ⭐</span></span>
<span class="line"><span>    ├── 函数的单调性</span></span>
<span class="line"><span>    ├── 函数的极值</span></span>
<span class="line"><span>    ├── 函数的最值</span></span>
<span class="line"><span>    ├── 函数的零点</span></span>
<span class="line"><span>    └── 不等式证明与恒成立问题</span></span></code></pre></div><h3 id="前后联系" tabindex="-1">前后联系 <a class="header-anchor" href="#前后联系" aria-label="Permalink to &quot;前后联系&quot;">​</a></h3><ul><li><strong>前置知识</strong>：函数、极限思想（直观理解）</li><li><strong>后续应用</strong>：大学微积分（积分、微分方程）</li><li><strong>跨学科联系</strong>：物理（瞬时速度、加速度）、经济（边际成本）、工程（优化设计）</li></ul><hr><h2 id="二、概念定义" tabindex="-1">二、概念定义 <a class="header-anchor" href="#二、概念定义" aria-label="Permalink to &quot;二、概念定义&quot;">​</a></h2><h3 id="_2-1-平均变化率" tabindex="-1">2.1 平均变化率 <a class="header-anchor" href="#_2-1-平均变化率" aria-label="Permalink to &quot;2.1 平均变化率&quot;">​</a></h3><p><strong>定义</strong>：函数f(x)从x₁到x₂的平均变化率为</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Δy/Δx = [f(x₂)-f(x₁)]/(x₂-x₁)</span></span></code></pre></div><p><strong>几何意义</strong>：割线斜率</p><p><strong>示例</strong>：</p><ul><li>位移从s(t₁)到s(t₂)的平均速度</li><li>成本从C(q₁)到C(q₂)的平均变化</li></ul><hr><h3 id="_2-2-瞬时变化率与导数-⭐" tabindex="-1">2.2 瞬时变化率与导数 ⭐ <a class="header-anchor" href="#_2-2-瞬时变化率与导数-⭐" aria-label="Permalink to &quot;2.2 瞬时变化率与导数 ⭐&quot;">​</a></h3><p><strong>导数定义</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>f&#39;(x₀) = lim(Δx→0) [f(x₀+Δx)-f(x₀)]/Δx</span></span></code></pre></div><p><strong>理解</strong>：</p><ul><li>平均变化率当Δx→0时的极限</li><li>瞬时变化率</li><li>几何意义：<strong>切线斜率</strong></li></ul><p><strong>导函数</strong>：f&#39;(x)或y&#39;或dy/dx</p><ul><li>将每一点的导数作为函数值，形成的新函数</li></ul><hr><h3 id="_2-3-导数的几何意义" tabindex="-1">2.3 导数的几何意义 <a class="header-anchor" href="#_2-3-导数的几何意义" aria-label="Permalink to &quot;2.3 导数的几何意义&quot;">​</a></h3><p><strong>核心</strong>：函数y=f(x)在点(x₀,f(x₀))处的导数f&#39;(x₀)就是曲线在该点处<strong>切线的斜率</strong>。</p><p><strong>切线方程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>y - f(x₀) = f&#39;(x₀)(x - x₀)</span></span></code></pre></div><p><strong>法线方程</strong>（垂直于切线）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>y - f(x₀) = -[1/f&#39;(x₀)](x - x₀)  （f&#39;(x₀)≠0）</span></span></code></pre></div><hr><h3 id="_2-4-基本初等函数的导数" tabindex="-1">2.4 基本初等函数的导数 <a class="header-anchor" href="#_2-4-基本初等函数的导数" aria-label="Permalink to &quot;2.4 基本初等函数的导数&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">函数</th><th style="text-align:center;">导数</th><th style="text-align:center;">备注</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>常数</strong> c</td><td style="text-align:center;">0</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><strong>幂函数</strong> xⁿ</td><td style="text-align:center;">nxⁿ⁻¹</td><td style="text-align:center;">n为实数</td></tr><tr><td style="text-align:center;"><strong>指数</strong> eˣ</td><td style="text-align:center;">eˣ</td><td style="text-align:center;">特殊的：导数等于自身</td></tr><tr><td style="text-align:center;"><strong>指数</strong> aˣ</td><td style="text-align:center;">aˣ·ln a</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><strong>对数</strong> ln x</td><td style="text-align:center;">1/x</td><td style="text-align:center;">x&gt;0</td></tr><tr><td style="text-align:center;"><strong>对数</strong> logₐx</td><td style="text-align:center;">1/(x·ln a)</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><strong>正弦</strong> sin x</td><td style="text-align:center;">cos x</td><td style="text-align:center;"></td></tr><tr><td style="text-align:center;"><strong>余弦</strong> cos x</td><td style="text-align:center;">-sin x</td><td style="text-align:center;">注意负号</td></tr></tbody></table><p><strong>记忆技巧</strong>：</p><ul><li>sin→cos→(-sin)→(-cos)→sin（循环求导）</li><li>(eˣ)&#39; = eˣ，因为e的定义就是使得这个成立的数</li></ul><hr><h3 id="_2-5-导数的四则运算" tabindex="-1">2.5 导数的四则运算 <a class="header-anchor" href="#_2-5-导数的四则运算" aria-label="Permalink to &quot;2.5 导数的四则运算&quot;">​</a></h3><p><strong>加法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[f(x) ± g(x)]&#39; = f&#39;(x) ± g&#39;(x)</span></span></code></pre></div><p><strong>乘法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[f(x)·g(x)]&#39; = f&#39;(x)g(x) + f(x)g&#39;(x)</span></span></code></pre></div><p><strong>除法</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[f(x)/g(x)]&#39; = [f&#39;(x)g(x) - f(x)g&#39;(x)] / [g(x)]²</span></span></code></pre></div><p><strong>记忆</strong>：</p><ul><li>乘法：&quot;前导后不导 + 前不导后导&quot;</li><li>除法：&quot;上导下不导 - 上不导下导，除以平方&quot;</li></ul><hr><h3 id="_2-6-复合函数求导-链式法则-⭐" tabindex="-1">2.6 复合函数求导（链式法则）⭐ <a class="header-anchor" href="#_2-6-复合函数求导-链式法则-⭐" aria-label="Permalink to &quot;2.6 复合函数求导（链式法则）⭐&quot;">​</a></h3><p><strong>法则</strong>：若y=f(u)，u=g(x)，则</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dy/dx = dy/du · du/dx = f&#39;(u) · g&#39;(x)</span></span></code></pre></div><p><strong>口诀</strong>：&quot;由外到内，层层求导，连乘起来&quot;</p><p><strong>示例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>y = sin(2x+1)</span></span>
<span class="line"><span>设u = 2x+1，则y = sin u</span></span>
<span class="line"><span>y&#39; = cos u · 2 = 2cos(2x+1)</span></span></code></pre></div><p><strong>常见复合函数</strong>：</p><ul><li>e^(ax+b) → a·e^(ax+b)</li><li>ln(ax+b) → a/(ax+b)</li><li>sin(ax+b) → a·cos(ax+b)</li><li>(ax+b)ⁿ → n·a·(ax+b)ⁿ⁻¹</li></ul><hr><h2 id="三、导数应用-⭐" tabindex="-1">三、导数应用 ⭐ <a class="header-anchor" href="#三、导数应用-⭐" aria-label="Permalink to &quot;三、导数应用 ⭐&quot;">​</a></h2><h3 id="_3-1-函数的单调性" tabindex="-1">3.1 函数的单调性 <a class="header-anchor" href="#_3-1-函数的单调性" aria-label="Permalink to &quot;3.1 函数的单调性&quot;">​</a></h3><p><strong>定理</strong>：</p><ul><li>f&#39;(x) &gt; 0 → f(x)<strong>单调递增</strong></li><li>f&#39;(x) &lt; 0 → f(x)<strong>单调递减</strong></li><li>f&#39;(x) = 0 → 可能是极值点</li></ul><p><strong>求单调区间步骤</strong>：</p><ol><li>求f&#39;(x)</li><li>解f&#39;(x)=0，得临界点</li><li>列表分析各区间f&#39;(x)的符号</li><li>确定单调区间</li></ol><hr><h3 id="_3-2-函数的极值" tabindex="-1">3.2 函数的极值 <a class="header-anchor" href="#_3-2-函数的极值" aria-label="Permalink to &quot;3.2 函数的极值&quot;">​</a></h3><p><strong>定义</strong>：</p><ul><li><strong>极大值</strong>：在x₀附近，f(x₀)比两侧都大</li><li><strong>极小值</strong>：在x₀附近，f(x₀)比两侧都小</li></ul><p><strong>求极值步骤</strong>：</p><ol><li>求f&#39;(x)</li><li>解f&#39;(x)=0，得驻点</li><li>判断驻点两侧导数符号变化 <ul><li>左正右负→极大值</li><li>左负右正→极小值</li><li>同号→不是极值点</li></ul></li></ol><p><strong>注意</strong>：</p><ul><li>极值是局部概念，不是最值</li><li>f&#39;(x₀)=0只是必要条件，不是充分条件</li></ul><hr><h3 id="_3-3-函数的最值" tabindex="-1">3.3 函数的最值 <a class="header-anchor" href="#_3-3-函数的最值" aria-label="Permalink to &quot;3.3 函数的最值&quot;">​</a></h3><p><strong>闭区间上求最值</strong>：</p><ol><li>求f&#39;(x)，找驻点</li><li>求驻点和端点的函数值</li><li>比较大小，最大的为最大值，最小的为最小值</li></ol><p><strong>实际应用中的最值问题</strong>：</p><ul><li>面积最大、体积最大</li><li>成本最低、利润最大</li><li>用料最省</li></ul><p><strong>建模步骤</strong>：</p><ol><li>设变量，建立目标函数</li><li>确定定义域（实际约束）</li><li>求导，找极值点</li><li>比较极值点和端点，确定最值</li></ol><hr><h3 id="_3-4-函数的零点" tabindex="-1">3.4 函数的零点 <a class="header-anchor" href="#_3-4-函数的零点" aria-label="Permalink to &quot;3.4 函数的零点&quot;">​</a></h3><p><strong>利用导数研究零点</strong>：</p><ol><li>求f&#39;(x)，确定单调性</li><li>找极值点，计算极值</li><li>结合极值符号和区间端点值，判断零点个数</li></ol><p><strong>零点存在性</strong>：</p><ul><li>若连续函数在区间端点异号，则区间内至少有一个零点</li><li>结合单调性可确定唯一性</li></ul><hr><h3 id="_3-5-不等式证明" tabindex="-1">3.5 不等式证明 <a class="header-anchor" href="#_3-5-不等式证明" aria-label="Permalink to &quot;3.5 不等式证明&quot;">​</a></h3><p><strong>常用方法</strong>：</p><p><strong>法1：构造函数</strong></p><ul><li>要证f(x) &gt; g(x)，设h(x) = f(x) - g(x)</li><li>证明h(x) &gt; 0（求h(x)的最小值）</li></ul><p><strong>法2：利用单调性</strong></p><ul><li>证明f(x)在[a,+∞)递增，且f(a)≥0</li><li>则f(x)≥f(a)≥0</li></ul><p><strong>法3：放缩法</strong></p><ul><li>利用已知不等式（如eˣ ≥ x+1，ln x ≤ x-1）</li></ul><hr><h3 id="_3-6-恒成立问题" tabindex="-1">3.6 恒成立问题 <a class="header-anchor" href="#_3-6-恒成立问题" aria-label="Permalink to &quot;3.6 恒成立问题&quot;">​</a></h3><p><strong>常见类型</strong>：</p><p><strong>类型1</strong>：f(x) ≥ 0在区间I上恒成立</p><ul><li>求f(x)在I上的最小值≥0</li></ul><p><strong>类型2</strong>：f(x) ≤ 0在区间I上恒成立</p><ul><li>求f(x)在I上的最大值≤0</li></ul><p><strong>类型3</strong>：f(x) ≥ g(x)恒成立</p><ul><li>转化为h(x) = f(x) - g(x) ≥ 0</li></ul><p><strong>分离参数法</strong>：</p><ul><li>若不等式可化为a ≥ φ(x)或a ≤ φ(x)</li><li>则a ≥ φ(x)ₘₐₓ 或 a ≤ φ(x)ₘᵢₙ</li></ul><hr><h2 id="四、典型例题" tabindex="-1">四、典型例题 <a class="header-anchor" href="#四、典型例题" aria-label="Permalink to &quot;四、典型例题&quot;">​</a></h2><h3 id="例题1-导数计算" tabindex="-1">例题1：导数计算 <a class="header-anchor" href="#例题1-导数计算" aria-label="Permalink to &quot;例题1：导数计算&quot;">​</a></h3><p><strong>题目</strong>：求下列函数的导数</p><ul><li>(1) y = x³ - 2x² + 3x - 1</li><li>(2) y = x·eˣ</li><li>(3) y = ln(2x+1)</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1) y&#39; = 3x² - 4x + 3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(2) y&#39; = (x)&#39;·eˣ + x·(eˣ)&#39; = eˣ + x·eˣ = (1+x)eˣ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>(3) 设u = 2x+1，则y = ln u</span></span>
<span class="line"><span>    y&#39; = (1/u) · 2 = 2/(2x+1)</span></span></code></pre></div><hr><h3 id="例题2-切线方程" tabindex="-1">例题2：切线方程 <a class="header-anchor" href="#例题2-切线方程" aria-label="Permalink to &quot;例题2：切线方程&quot;">​</a></h3><p><strong>题目</strong>：求曲线y = x³ - 2x在点(1,-1)处的切线方程。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>y&#39; = 3x² - 2</span></span>
<span class="line"><span>x=1时，y&#39; = 3-2 = 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>切线方程：y - (-1) = 1·(x-1)</span></span>
<span class="line"><span>即 y = x - 2</span></span></code></pre></div><hr><h3 id="例题3-单调性与极值" tabindex="-1">例题3：单调性与极值 <a class="header-anchor" href="#例题3-单调性与极值" aria-label="Permalink to &quot;例题3：单调性与极值&quot;">​</a></h3><p><strong>题目</strong>：求f(x) = x³ - 3x²的单调区间和极值。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>f&#39;(x) = 3x² - 6x = 3x(x-2)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>令f&#39;(x)=0，得x=0或x=2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>列表分析：</span></span>
<span class="line"><span>x       (-∞,0)   0   (0,2)   2   (2,+∞)</span></span>
<span class="line"><span>f&#39;(x)      +      0     -     0      +</span></span>
<span class="line"><span>f(x)      ↗    极大   ↘   极小    ↗</span></span>
<span class="line"><span></span></span>
<span class="line"><span>单调增区间：(-∞,0)和(2,+∞)</span></span>
<span class="line"><span>单调减区间：(0,2)</span></span>
<span class="line"><span>极大值：f(0) = 0</span></span>
<span class="line"><span>极小值：f(2) = 8-12 = -4</span></span></code></pre></div><hr><h3 id="例题4-最值应用" tabindex="-1">例题4：最值应用 <a class="header-anchor" href="#例题4-最值应用" aria-label="Permalink to &quot;例题4：最值应用&quot;">​</a></h3><p><strong>题目</strong>：用长为60cm的铁丝围成一个矩形，问长宽各为多少时面积最大？</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>设长为x，则宽为(30-x)</span></span>
<span class="line"><span>面积S = x(30-x) = 30x - x²  (0&lt;x&lt;30)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>S&#39; = 30 - 2x</span></span>
<span class="line"><span>令S&#39;=0，得x=15</span></span>
<span class="line"><span></span></span>
<span class="line"><span>S&#39;&#39; = -2 &lt; 0，故x=15是极大值点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当x=15时，宽也是15（正方形）</span></span>
<span class="line"><span>最大面积S = 225 cm²</span></span></code></pre></div><hr><h2 id="五、配套练习" tabindex="-1">五、配套练习 <a class="header-anchor" href="#五、配套练习" aria-label="Permalink to &quot;五、配套练习&quot;">​</a></h2><h3 id="基础练习-必做" tabindex="-1">基础练习（必做） <a class="header-anchor" href="#基础练习-必做" aria-label="Permalink to &quot;基础练习（必做）&quot;">​</a></h3><p><strong>练习1</strong>：求下列函数的导数</p><ul><li>(1) y = 3x⁴ - 2x³ + x - 5</li><li>(2) y = x²·ln x</li><li>(3) y = e^(3x-1)</li></ul><p><strong>练习2</strong>：求曲线y = x² + 1在点(2,5)处的切线方程。</p><p><strong>练习3</strong>：求f(x) = x³ - 6x² + 9x的单调区间和极值。</p><p><strong>练习4</strong>：证明当x &gt; 0时，eˣ &gt; x+1。</p><p><strong>参考答案</strong>：</p><ul><li>练习1：(1) 12x³-6x²+1；(2) 2x·ln x + x；(3) 3e^(3x-1)</li><li>练习2：y = 4x - 3</li><li>练习3：增区间(-∞,1)和(3,+∞)，减区间(1,3)；极大值4，极小值0</li><li>练习4：设f(x)=eˣ-x-1，f&#39;(x)=eˣ-1&gt;0(x&gt;0)，f(0)=0，∴f(x)&gt;0</li></ul><hr><h3 id="提高练习-选做" tabindex="-1">提高练习（选做） <a class="header-anchor" href="#提高练习-选做" aria-label="Permalink to &quot;提高练习（选做）&quot;">​</a></h3><p><strong>练习5</strong>：求f(x) = x·e⁻ˣ的单调区间、极值和最值。</p><p><strong>练习6</strong>：已知f(x) = x³ + ax² + bx + c在x=1处有极值-1，且f(0)=0，求a,b,c。</p><hr><h2 id="六、faq常见问题" tabindex="-1">六、FAQ常见问题 <a class="header-anchor" href="#六、faq常见问题" aria-label="Permalink to &quot;六、FAQ常见问题&quot;">​</a></h2><h3 id="faq-1-复合函数求导总漏乘内层导数" tabindex="-1">FAQ 1：复合函数求导总漏乘内层导数 <a class="header-anchor" href="#faq-1-复合函数求导总漏乘内层导数" aria-label="Permalink to &quot;FAQ 1：复合函数求导总漏乘内层导数&quot;">​</a></h3><p><strong>错误示例</strong>：</p><ul><li>y = sin(2x)，y&#39; = cos(2x) ✗（漏乘2）</li><li>正确：y&#39; = 2cos(2x)</li></ul><p><strong>检查方法</strong>：</p><ul><li>每次求导后检查：是否还有内层函数需要求导</li><li>口诀：&quot;由外到内，层层求导，连乘起来&quot;</li></ul><hr><h3 id="faq-2-导数与单调性的关系总搞反" tabindex="-1">FAQ 2：导数与单调性的关系总搞反 <a class="header-anchor" href="#faq-2-导数与单调性的关系总搞反" aria-label="Permalink to &quot;FAQ 2：导数与单调性的关系总搞反&quot;">​</a></h3><p><strong>记忆</strong>：</p><ul><li>f&#39;(x) &gt; 0 → f(x) <strong>增</strong>（导数为正，函数上升）</li><li>f&#39;(x) &lt; 0 → f(x) <strong>减</strong>（导数为负，函数下降）</li></ul><p><strong>注意</strong>：</p><ul><li>f&#39;(x) &gt; 0是充分条件，不是必要条件</li><li>f(x)递增时，可能有f&#39;(x)=0的点（如f(x)=x³在x=0处）</li></ul><hr><h3 id="faq-3-极值点和最值点分不清" tabindex="-1">FAQ 3：极值点和最值点分不清 <a class="header-anchor" href="#faq-3-极值点和最值点分不清" aria-label="Permalink to &quot;FAQ 3：极值点和最值点分不清&quot;">​</a></h3><p><strong>区别</strong>：</p><ul><li><strong>极值点</strong>：局部概念，只要在附近最大/最小即可</li><li><strong>最值点</strong>：全局概念，整个区间内最大/最小</li></ul><p><strong>联系</strong>：</p><ul><li>开区间内，最值点一定是极值点</li><li>闭区间内，最值点可能是极值点或端点</li></ul><hr><h3 id="faq-4-恒成立问题不知道怎么转化" tabindex="-1">FAQ 4：恒成立问题不知道怎么转化 <a class="header-anchor" href="#faq-4-恒成立问题不知道怎么转化" aria-label="Permalink to &quot;FAQ 4：恒成立问题不知道怎么转化&quot;">​</a></h3><p><strong>转化策略</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">原问题</th><th style="text-align:left;">转化</th></tr></thead><tbody><tr><td style="text-align:center;">f(x) ≥ 0恒成立</td><td style="text-align:left;">f(x)ₘᵢₙ ≥ 0</td></tr><tr><td style="text-align:center;">f(x) ≤ 0恒成立</td><td style="text-align:left;">f(x)ₘₐₓ ≤ 0</td></tr><tr><td style="text-align:center;">f(x) ≥ g(x)恒成立</td><td style="text-align:left;">[f(x)-g(x)]ₘᵢₙ ≥ 0</td></tr><tr><td style="text-align:center;">存在x使f(x) ≥ 0</td><td style="text-align:left;">f(x)ₘₐₓ ≥ 0</td></tr></tbody></table><p><strong>注意</strong>：</p><ul><li>&quot;恒成立&quot;对应最值</li><li>&quot;存在&quot;对应极值</li></ul><hr><h2 id="七、本章检查清单" tabindex="-1">七、本章检查清单 <a class="header-anchor" href="#七、本章检查清单" aria-label="Permalink to &quot;七、本章检查清单&quot;">​</a></h2><ul><li>[ ] 理解导数的定义（瞬时变化率）</li><li>[ ] 掌握基本初等函数的导数公式</li><li>[ ] 熟练运用四则运算法则</li><li>[ ] 熟练运用复合函数求导（链式法则）</li><li>[ ] 会求切线方程</li><li>[ ] 会利用导数判断函数单调性</li><li>[ ] 会求函数的极值和最值</li><li>[ ] 能解决简单的恒成立问题</li></ul><hr><p><strong>文档编号</strong>: Math-Learn-Detail-003<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,173)])])}const c=s(e,[["render",i]]);export{x as __pageData,c as default};
